    void transformBytesToLong(byte[] a, byte[] b) {
        this.r = new long[16];
        this.p = 0;
        int sIndex = 0;
        int i = 0;
        while (i < a.length) {
            this.r[sIndex++] = SaltMix.bytes2long(a, i);
            i += 8;
        }
        i = 0;
        while (i < b.length) {
            this.r[sIndex++] = SaltMix.bytes2long(b, i);
            i += 8;
        }
    }

